mapper.update:
UPDATE FWK_USER_WORK_GROUP
SET
    GROUP_NAME          = #{dto.groupName},
    GROUP_ORDER         = #{dto.groupOrder, jdbcType=INTEGER},
    LAST_UPDATE_DTIME   = #{lastUpdateDtime},
    LAST_UPDATE_USER_ID = #{lastUpdateUserId}
WHERE USER_ID  = #{dto.userId}
  AND GROUP_ID = #{dto.groupId}

mapper.delete:
DELETE FROM FWK_USER_WORK_GROUP
WHERE USER_ID  = #{userId}
  AND GROUP_ID = #{groupId}

mapper.select:
SELECT COUNT(*)
FROM FWK_USER_WORK_GROUP
WHERE USER_ID  = #{userId}
  AND GROUP_ID = #{groupId}

